class StringSearcher {
    int findFirstOccurrenceOf(String searchTerm, String text) {
        if (searchTerm == null || text == null) return -1;
        return text.indexOf(searchTerm);
    }

    boolean containsSearchTerm(String searchTerm, String text) {
        return findFirstOccurrenceOf(searchTerm, text) != -1;
    }
}
